   VmServiceClient get client => _client;

   @internal
   Future<Observation> pullObservation({
     StabilityPolicy policy = StabilityPolicy.actionRelative,
   }) {
     _ensureStarted('pullObservation');
     return _puller.pull(policy: policy);
   }
   ```
