       required List<ToolDescriptor> coreTools,
       required Map<String, List<ToolDescriptor>> pluginTools,
       required String goal,
       required String agentsMd,
       StabilityPolicy policy = StabilityPolicy.actionRelative,
     })  : _session = session,
