       _session.disablePlugin(namespace, reason);
     }
   }
   ```
   Test: `dart analyze packages/exploration_agent` → 0 issues
   Commit: `feat(exploration_agent): idempotent disablePlugin`

5. Implement `observe`, `executeAction`, `notifyPlugins`, transport translation — same file

   ```dart
   @override
   Future<Observation> observe() => _callTransport(
     () => _session.pullObservation(policy: _policy));

   @override
   Future<Map<String, dynamic>> executeAction(
     String tool, Map<String, dynamic> args,
   ) => _callTransport(() => _session.client.executeAction(tool, args));

   @override
   Future<void> notifyPlugins(
     String tool, Map<String, dynamic> args, Map<String, dynamic> result,
   ) async {/* binding-side dispatch already ran in executeAction */}

   static const Set<int> _transportCodes = <int>{-32000, -32603};

   Future<T> _callTransport<T>(Future<T> Function() body) async {
     try {
       return await body();
     } on RPCError catch (e) {
       final m = e.message.toLowerCase();
       if (_transportCodes.contains(e.code) ||
           m.contains('disposed') || m.contains('connection closed')) {
         throw VmServiceConnectionLost(e);
       }
       rethrow;
     } on StateError catch (e) {
       throw VmServiceConnectionLost(e); // VmService throws after dispose
     }
   }
   ```
   Test: `dart analyze packages/exploration_agent` → 0 issues
   Commit: `feat(exploration_agent): transport-error translation`

