   class PluginDiffAdded extends PluginDiff {
     final dynamic current; // toJson => {'kind':'added','current':...}
   }
   class PluginDiffRemoved extends PluginDiff {
     final dynamic previous; // toJson => {'kind':'removed','previous':...}
   }
