   abstract class _CoreTool extends ExplorationTool {
     _CoreTool(this.plugin);
     final CorePlugin plugin;
     ToolResult _terminatedIfNeeded() => plugin.terminated
       ? ToolResult(ok: false, error: 'session_terminated: terminal action issued')
       : null!;
   }

   Future<ToolResult> dispatchSemanticsActionOrHitTest(
     SemanticsNode node, SemanticsAction action,
     {Object? actionArgs, required Future<void> Function(Rect rect) fallback,
   }) async {
     final hasIt = (node.getSemanticsData().actions & action.index) != 0;
     if (hasIt) {
       node.performAction(action, actionArgs);
     } else {
       await fallback(node.transform == null
         ? node.rect
         : MatrixUtils.transformRect(node.transform!, node.rect));
     }
     return ToolResult(ok: true, value: const <String, Object?>{});
   }

