   ```dart
   import '../provider/types.dart';
   import '../types.dart';

   /// Build `Map<namespace, List<ToolDescriptor>>` from a whitelist intersected
   /// with the binding's handshake manifest. Pure Dart (web-safe).
   /// Empty `requested` → empty map. Namespaces in `requested` absent from
   /// the handshake are dropped. Tools emit a permissive object inputSchema
   /// until cx6.39 plumbs real schemas through.
   Map<String, List<ToolDescriptor>> buildPluginTools({
     required Iterable<String> requested,
     required List<PluginManifestEntry> handshake,
   }) {
     if (requested.isEmpty) return const <String, List<ToolDescriptor>>{};
     final wanted = requested.toSet();
     final out = <String, List<ToolDescriptor>>{};
     for (final p in handshake) {
       if (!wanted.contains(p.namespace)) continue;
       out[p.namespace] = <ToolDescriptor>[
         for (final n in p.tools)
           ToolDescriptor(
             name: n,
             description:
                 'Plugin tool $n (permissive schema; cx6.39 plumbs real one).',
             inputSchema: const {'type': 'object', 'additionalProperties': true},
           ),
       ];
     }
     return out;
   }

   List<String> unknownPluginNamespaces({
     required Iterable<String> requested,
     required List<PluginManifestEntry> handshake,
   }) {
     final active = {for (final p in handshake) p.namespace};
     return [for (final ns in requested) if (!active.contains(ns)) ns];
   }
   ```
