   ```dart
   import 'dart:async';
   import 'dart:convert';
   import 'package:exploration_agent/exploration_agent.dart';

   /// In-memory [TrajectorySink] that re-broadcasts each line as a parsed
   /// [TrajectoryRecord] on [records]. Backs the panel's in-flight
   /// TrajectoryWriter; the disk-backed DtdTrajectorySink (already in this
   /// package) is the future production successor for persistence.
   class BroadcastTrajectorySink implements TrajectorySink {
     final _ctrl = StreamController<TrajectoryRecord>.broadcast();
     bool _closed = false;
     Stream<TrajectoryRecord> get records => _ctrl.stream;
     @override Future<void> writeLine(String line) async {
       if (_closed) throw StateError('BroadcastTrajectorySink is closed');
       _ctrl.add(TrajectoryRecord.fromJson(jsonDecode(line) as Map<String, dynamic>));
     }
     @override Future<void> flush() async {}
     @override Future<void> close() async {
       if (_closed) return;
       _closed = true;
       await _ctrl.close();
     }
   }
   ```
