2. TimelineSource abstraction — `exploration_devtools/lib/src/timeline/timeline_source.dart`

   ```dart
   abstract class TimelineSource {
     ValueListenable<List<TrajectoryRecord>> get records;
     Future<void> close();
   }
   class LiveTimelineSource implements TimelineSource {
     final _list = ValueNotifier<List<TrajectoryRecord>>(const []);
     late final StreamSubscription<TrajectoryRecord> _sub;
     LiveTimelineSource(Stream<TrajectoryRecord> source) {
       _sub = source.listen((r) =>
         _list.value = List.unmodifiable([..._list.value, r]));
     }
     @override get records => _list;
     @override Future<void> close() async { await _sub.cancel(); _list.dispose(); }
   }
   class BrowseTimelineSource implements TimelineSource {
     final _list = ValueNotifier<List<TrajectoryRecord>>(const []);
     BrowseTimelineSource.fromJsonl(String jsonl) {
       _list.value = TrajectoryReader.readAll(jsonl);
     }
     @override get records => _list;
     @override Future<void> close() async { _list.dispose(); }
   }
   ```

