4. `ThinkingPanelController` — `packages/exploration_devtools/lib/src/thinking/thinking_panel_controller.dart` (created)

   Subscribes to `session.turnEvents`; routes deltas to text controller; clears buffer on new turn; appends action+validation lines; tracks auto-scroll state; cleans up on dispose.

   ```dart
   import 'dart:async';
   import 'package:exploration_agent/exploration_agent.dart';
   import 'package:flutter/foundation.dart';
   import 'append_only_text_controller.dart';
   class ThinkingPanelController {
     ThinkingPanelController(this._session);
     final ExplorationSession _session;
     final AppendOnlyTextController text = AppendOnlyTextController();
     final ValueNotifier<bool> autoScroll = ValueNotifier<bool>(true);
     final ValueNotifier<int> currentTurn = ValueNotifier<int>(0);
     StreamSubscription<TurnEvent>? _sub;
     void start() { _sub = _session.turnEvents.listen(_onEvent); }
     void _onEvent(TurnEvent e) {
       if (e is TurnThinking) {
         if (e.turn != currentTurn.value) { text.clear(); currentTurn.value = e.turn; }
         text.append(e.delta.text);
       } else if (e is TurnActionDecided) {
         text.append('\n\nAction: ${e.toolName}(${_args(e.args)})');
       } else if (e is TurnValidation) {
         text.append('\nValidation: ${e.ok ? "ok" : "reject: ${e.rejectReason ?? "(no reason)"}"}\n');
       }
     }
     static String _args(Map<String, dynamic> a) => a.entries
       .map((kv) => '${kv.key}: ${kv.value is String ? '"${kv.value}"' : kv.value}').join(', ');
     void pauseAutoScroll() => autoScroll.value = false;
     void resumeAutoScroll() => autoScroll.value = true;
     Future<void> dispose() async {
       await _sub?.cancel(); _sub = null;
       text.dispose(); autoScroll.dispose(); currentTurn.dispose();
     }
   }
   ```

