       final s = await ExplorationSession.connect(Uri.parse(uri));
       setState(() => _session = s);
       return s;
     }
     Future<void> endSession() async {
       final s = _session; if (s == null) return;
       await s.end(); setState(() => _session = null);
     }
     @override void dispose() { _session?.end(); super.dispose(); }
     @override Widget build(BuildContext c) => widget.child;
   }
