2. Argument parser + tier/policy enums — `packages/exploration_cli/lib/src/cli_args.dart`

   ```dart
   import 'package:args/args.dart';

   enum ModelTier { qwenMlx, claude, openai }
   enum StabilityPolicy { idle, frameStable, actionRelative }

   class CliArgs {
     final String? goal; final Uri vmUri; final ModelTier tier;
     final String? outputPath; final StabilityPolicy policy; final List<String> plugins;
     const CliArgs({required this.goal, required this.vmUri, required this.tier,
       required this.outputPath, required this.policy, required this.plugins});
   }
   class CliUsageError extends ArgumentError { CliUsageError(String m) : super(m); }

   ArgParser buildParser() => ArgParser()
     ..addOption('goal', help: 'Exploration goal (or pipe via stdin).')
     ..addOption('vm-uri', mandatory: true, help: 'Flutter VM service ws:// URI.')
     ..addOption('model', defaultsTo: 'qwen-mlx',
         allowed: ['qwen-mlx', 'claude', 'openai'], help: 'Model tier (PRD 16.4).')
     ..addOption('output', help: 'Trajectory path (default ./trajectories/<UTC>.jsonl).')
     ..addOption('policy', defaultsTo: 'action-relative',
         allowed: ['idle', 'frame-stable', 'action-relative'], help: 'Stability policy.')
     ..addOption('plugins', defaultsTo: '', help: 'Comma-separated plugin namespaces.')
     ..addFlag('help', abbr: 'h', negatable: false);

   CliArgs parseCliArgs(List<String> argv) {
     final p = buildParser();
     final ArgResults res;
     try { res = p.parse(argv); }
     on FormatException catch (e) { throw CliUsageError(e.message); }
     if (res['vm-uri'] == null) throw CliUsageError('Missing required flag: --vm-uri');
     final vm = Uri.tryParse(res['vm-uri'] as String);
     if (vm == null) throw CliUsageError('Invalid --vm-uri');
     final tier = switch (res['model']) {
       'qwen-mlx' => ModelTier.qwenMlx, 'claude' => ModelTier.claude,
       'openai' => ModelTier.openai, _ => throw CliUsageError('Invalid --model'),
     };
     final policy = switch (res['policy']) {
       'idle' => StabilityPolicy.idle, 'frame-stable' => StabilityPolicy.frameStable,
       'action-relative' => StabilityPolicy.actionRelative,
       _ => throw CliUsageError('Invalid --policy'),
     };
     final ps = (res['plugins'] as String).trim();
     return CliArgs(goal: res['goal'] as String?, vmUri: vm, tier: tier,
       outputPath: res['output'] as String?, policy: policy,
       plugins: ps.isEmpty ? const [] :
         ps.split(',').map((s) => s.trim()).where((s) => s.isNotEmpty).toList());
   }
   ```

