3. Add `TrajectoryWriter` — `packages/exploration_agent/lib/src/trajectory/writer.dart`

   Serializes typed records to one JSON line each, flushing the sink after every write (PRD §14 per-record recovery guarantee). `close()` always emits the footer (even on `harness_error`) and is idempotent; the loop driver (.18) wraps its outermost try/finally around `close()`.

   ```dart
   import 'dart:convert';
   import 'records.dart';
   import 'sink.dart';

   class TrajectoryWriter {
     final TrajectorySink _sink;
     bool _closed = false, _headerWritten = false;
     TrajectoryWriter(this._sink);

     Future<void> writeHeader(SessionHeader h) async {
       _ensureOpen();
       if (_headerWritten) throw StateError('Trajectory header already written');
       _headerWritten = true;
       await _writeAndFlush(h.toJson());
     }
     Future<void> writeTurn(TurnRecord t) async {
       _ensureOpen(); _ensureHeader();
       await _writeAndFlush(t.toJson());
     }
     Future<void> writePluginDisabled(PluginDisabledEvent e) async {
       _ensureOpen(); _ensureHeader();
       await _writeAndFlush(e.toJson());
     }
     Future<void> close(SessionFooter footer) async {
       if (_closed) return;
       _closed = true;
       await _writeAndFlush(footer.toJson());
       await _sink.close();
     }

     Future<void> _writeAndFlush(Map<String, dynamic> j) async {
       await _sink.writeLine(jsonEncode(j));
       await _sink.flush();
     }
     void _ensureOpen() {
       if (_closed) throw StateError('TrajectoryWriter is closed');
     }
     void _ensureHeader() {
       if (!_headerWritten) throw StateError('writeHeader must precede turns/events');
     }
   }
   ```

